    transparent 0%,
    $color-accent 30%,
    $color-accent-hover 50%,
    $color-accent 70%,
    transparent 100%
  );
  background-size: 200% 100%;
  animation: loading-bar-slide 1.5s ease-in-out infinite;
}

@keyframes loading-bar-slide {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

